fn solve(value: Vec<i64>, limit: Vec<i64>) -> i64 {
    let n = value.len();
    let mut arr: Vec<(i64, i64)> = value.into_iter().zip(limit.into_iter()).collect();

    arr.sort_by(|a, b| {
        if a.1 != b.1 {
            a.1.cmp(&b.1)
        } else {
            b.0.cmp(&a.0)
        }
    });

    let mut active_count = 0;
    let mut total_sum = 0;

    for &(val, lim) in arr.iter() {
        if active_count < lim {
            total_sum += val;
            active_count += 1;
        }
    }

    total_sum
}
```

